use base64::{engine::general_purpose, Engine as _};
use flate2::read::GzDecoder;
use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::io::Read;

pub const COMPRESSED_INVENTORY: &str = "";

#[derive(Clone, Debug, Deserialize, Serialize)]
pub struct InventoryItem {
    pub id: String,
    pub title: String,
    pub svg_url: String,
}

pub fn fallback_svg_url(id: &str, path_part: &str) -> String {
    format!("https://cdn.undraw.co/{}/{}.svg", path_part, id)
}

fn normalize_inventory_item(value: Value) -> Option<InventoryItem> {
    if let Some(items) = value.as_array() {
        let id = items.first()?.as_str()?;
        let title = items.get(1)?.as_str()?;
        return Some(InventoryItem {
            id: id.to_string(),
            title: title.to_string(),
            svg_url: fallback_svg_url(id, "illustration"),
        });
    }

    let id = value.get("id").or_else(|| value.get("newSlug"))?.as_str()?;
    let title = value.get("title")?.as_str()?;
    let svg_url = value
        .get("svg_url")
        .or_else(|| value.get("media"))?
        .as_str()?;

    Some(InventoryItem {
        id: id.to_string(),
        title: title.to_string(),
        svg_url: svg_url.to_string(),
    })
}

pub fn load_inventory() -> Option<Vec<InventoryItem>> {
    let decoded = general_purpose::STANDARD
        .decode(COMPRESSED_INVENTORY)
        .ok()?;
    let mut decoder = GzDecoder::new(&decoded[..]);
    let mut json_str = String::new();
    decoder.read_to_string(&mut json_str).ok()?;
    let values: Vec<Value> = serde_json::from_str(&json_str).ok()?;
    Some(
        values
            .into_iter()
            .filter_map(normalize_inventory_item)
            .collect(),
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_load_inventory() {
        let inv = load_inventory().expect("Failed to load inventory");
        assert!(!inv.is_empty());
        assert!(inv[0].svg_url.starts_with("https://cdn.undraw.co/"));
    }
}
